	const authForwardUrl = useQueryBypass
		? buildProxyUrlWithProtectionBypass(authProxyUrl, args.vercelProtectionBypassSecret)
		: authProxyUrl;
	const allow: Record<string, NetworkPolicyRule[]> = {
		[callbackHost]: [
			{
