		return commitResult;
	}

	const pushCommand = await runVercelSandboxCommand(sandbox, {
		cmd: "git",
		args: ["push", "origin", `HEAD:${branchName}`],
		cwd: repoPath,
	});

	return pushCommand.exitCode === 0
		? pushCommand
		: {
			...pushCommand,
		};
